46:     public static final KafkaPrincipal WILDCARD_PRINCIPAL = new KafkaPrincipal(KafkaPrincipal.USER_TYPE, "*");
47:     public static final String WILDCARD_PRINCIPAL_STRING = WILDCARD_PRINCIPAL.toString();
48:     public static final String WILDCARD_HOST = "*";
49:     public static final String WILDCARD_RESOURCE = ResourcePattern.WILDCARD_RESOURCE;
50:     public static final Set<AclOperation> ACL_OPERATIONS = Arrays.stream(AclOperation.values())
51:         .filter(t -> !(t == AclOperation.UNKNOWN || t == AclOperation.ANY))
52:         .collect(Collectors.toSet());
53: 
54:     public static Set<AclOperation> supportedOperations(ResourceType resourceType) {
55:         switch (resourceType) {
56:             case TOPIC:
57:                 return new HashSet<>(Arrays.asList(READ, WRITE, CREATE, DESCRIBE, DELETE, ALTER, DESCRIBE_CONFIGS, ALTER_CONFIGS));
58:             case GROUP:
59:                 return new HashSet<>(Arrays.asList(READ, DESCRIBE, DELETE, DESCRIBE_CONFIGS, ALTER_CONFIGS));
60:             case CLUSTER:
61:                 return new HashSet<>(Arrays.asList(CREATE, CLUSTER_ACTION, DESCRIBE_CONFIGS, ALTER_CONFIGS, IDEMPOTENT_WRITE, ALTER, DESCRIBE));
62:             case TRANSACTIONAL_ID:
63:                 return new HashSet<>(Arrays.asList(DESCRIBE, WRITE, TWO_PHASE_COMMIT));
64:             case DELEGATION_TOKEN:
65:                 return Set.of(DESCRIBE);
66:             case USER:
67:                 return new HashSet<>(Arrays.asList(CREATE_TOKENS, DESCRIBE_TOKENS));
68:             default:
69:                 throw new IllegalArgumentException("Not a concrete resource type");
70:         }
71:     }
