73:     public static Errors authorizationError(ResourceType resourceType) {
74:         switch (resourceType) {
75:             case TOPIC:
76:                 return Errors.TOPIC_AUTHORIZATION_FAILED;
77:             case GROUP:
78:                 return Errors.GROUP_AUTHORIZATION_FAILED;
79:             case CLUSTER:
80:                 return Errors.CLUSTER_AUTHORIZATION_FAILED;
81:             case TRANSACTIONAL_ID:
82:                 return Errors.TRANSACTIONAL_ID_AUTHORIZATION_FAILED;
83:             case DELEGATION_TOKEN:
84:                 return Errors.DELEGATION_TOKEN_AUTHORIZATION_FAILED;
85:             default:
86:                 throw new IllegalArgumentException("Authorization error type not known");
87:         }
88:     }
89: }
