29: /**
30:  * An immutable class that stores the ACLs in KRaft-based clusters.
31:  */
32: public class AclCache {
33:     /**
34:      * Contains all of the current ACLs sorted by (resource type, resource name).
35:      */
36:     private final ImmutableNavigableSet<StandardAcl> aclsByResource;
37: 
38:     /**
39:      * Contains all of the current ACLs indexed by UUID.
40:      */
41:     private final ImmutableMap<Uuid, StandardAcl> aclsById;
42: 
43:     AclCache() {
44:         this(ImmutableNavigableSet.empty(), ImmutableMap.empty());
45:     }
46: 
47:     private AclCache(final ImmutableNavigableSet<StandardAcl> aclsByResource, final ImmutableMap<Uuid, StandardAcl> aclsById) {
48:         this.aclsByResource = aclsByResource;
49:         this.aclsById = aclsById;
50:     }
51: 
52:     public ImmutableNavigableSet<StandardAcl> aclsByResource() {
53:         return aclsByResource;
54:     }
55: 
56:     Iterable<AclBinding> acls(AclBindingFilter filter) {
57:         List<AclBinding> aclBindingList = new ArrayList<>();
58:         aclsByResource.forEach(acl -> {
59:             AclBinding aclBinding = acl.toBinding();
60:             if (filter.matches(aclBinding)) {
61:                 aclBindingList.add(aclBinding);
62:             }
63:         });
64:         return aclBindingList;
65:     }
66: 
67:     int count() {
68:         return aclsById.size();
69:     }
70: 
71:     StandardAcl getAcl(Uuid id) {
72:         return aclsById.get(id);
73:     }
74: 
75:     AclCache addAcl(Uuid id, StandardAcl acl) {
76:         StandardAcl prevAcl = this.aclsById.get(id);
77:         if (prevAcl != null) {
78:             throw new RuntimeException("An ACL with ID " + id + " already exists.");
79:         }
80: 
81:         ImmutableMap<Uuid, StandardAcl> aclsById = this.aclsById.updated(id, acl);
82: 
83:         if (this.aclsByResource.contains(acl)) {
84:             throw new RuntimeException("Unable to add the ACL with ID " + id +
85:                     " to aclsByResource");
86:         }
87: 
88:         ImmutableNavigableSet<StandardAcl> aclsByResource = this.aclsByResource.added(acl);
89:         return new AclCache(aclsByResource, aclsById);
90:     }
91: 
92:     AclCache removeAcl(Uuid id) {
93:         StandardAcl acl = this.aclsById.get(id);
94:         if (acl == null) {
95:             throw new RuntimeException("ID " + id + " not found in aclsById.");
96:         }
97:         ImmutableMap<Uuid, StandardAcl> aclsById = this.aclsById.removed(id);
98: 
99:         if (!this.aclsByResource.contains(acl)) {
100:             throw new RuntimeException("Unable to remove the ACL with ID " + id +
101:                     " from aclsByResource");
102:         }
103: 
104:         ImmutableNavigableSet<StandardAcl> aclsByResource = this.aclsByResource.removed(acl);
105:         return new AclCache(aclsByResource, aclsById);
106:     }
107: }
